83	/// Run a command with retries, sleeping between attempts.
84	fn run_retry(
85	    cmd: &str,
86	    args: &[&str],
87	    cwd: &Path,
88	    retry: &PushRetryOptions,
89	) -> Result<String, Box<dyn std::error::Error>> {
90	    let mut last_err = String::new();
91	    for attempt in 1..=retry.push_retries {
92	        match run(cmd, args, cwd) {
93	            Ok(out) => {
94	                if attempt > 1 {
95	                    debug!("succeeded after {attempt} attempts");
96	                }
97	                return Ok(out);
98	            }
99	            Err(e) => {
100	                last_err = e.to_string();
101	                if attempt < retry.push_retries {
102	                    debug!(
103	                        "attempt {attempt}/{} failed: {last_err}",
104	                        retry.push_retries
105	                    );
106	                    debug!("retrying in {}s...", retry.push_retry_delay);
107	                    std::thread::sleep(std::time::Duration::from_secs(retry.push_retry_delay));
108	                }
109	            }
110	        }
111	    }
112	    Err(format!("failed after {} attempts: {last_err}", retry.push_retries).into())
113	}
