117	/// Parse the `--use-template` value into `(code, bot)` template paths.
118	///
119	/// Format: `CODE[,BOT]`. If `BOT` is omitted, the default is the sibling
120	/// directory whose name is `<CODE-basename>.claude` (via
121	/// `Path::with_file_name`, so a trailing slash on `CODE` does not produce
122	/// a different result).
123	pub(crate) fn parse_use_template(
124	    s: &str,
125	) -> Result<(PathBuf, PathBuf), Box<dyn std::error::Error>> {
126	    let mut parts = s.splitn(2, ',');
127	    let code_raw = parts.next().unwrap_or(""); // OK: splitn always yields at least one element
128	    let bot_raw = parts.next();
129	    let code_trim = code_raw.trim();
130	    if code_trim.is_empty() {
131	        return Err("--use-template: code template path is empty".into());
132	    }
133	    let code = PathBuf::from(code_trim);
134	    let bot = match bot_raw.map(str::trim) {
135	        Some(b) if !b.is_empty() => PathBuf::from(b),
136	        _ => {
137	            let file_name = code.file_name().ok_or_else(|| {
138	                format!(
139	                    "--use-template: cannot derive default bot path from '{}' (no file name component)",
140	                    code.display()
141	                )
142	            })?;
143	            let new_name = format!("{}.claude", file_name.to_string_lossy());
144	            code.with_file_name(new_name)
145	        }
146	    };
147	    Ok((code, bot))
148	}
