150	/// Top-level non-hidden files init writes. Kept here so that if init is
151	/// ever extended to write non-hidden top-level files, the pre-flight
152	/// conflict scan flags any template that would clash. Currently empty
153	/// because init only writes hidden files (`.vc-config.toml`, `.gitignore`),
154	/// and the template copy skips hidden entries.
155	const RESERVED_TEMPLATE_ENTRIES: &[&str] = &[];
156	
157	/// Validate one template directory: exists, is a directory, and has no
158	/// top-level non-hidden entry that would collide with init's own writes.
159	///
160	/// - `label` prefixes every error message (`code` / `bot`).
161	pub(crate) fn validate_template_one(
162	    label: &str,
163	    p: &Path,
164	) -> Result<(), Box<dyn std::error::Error>> {
165	    if !p.exists() {
166	        return Err(format!(
167	            "--use-template: {label} template '{}' does not exist",
168	            p.display()
169	        )
170	        .into());
171	    }
172	    if !p.is_dir() {
173	        return Err(format!(
174	            "--use-template: {label} template '{}' is not a directory",
175	            p.display()
176	        )
177	        .into());
178	    }
179	    for entry in std::fs::read_dir(p)? {
180	        let entry = entry?;
181	        let name = entry.file_name();
182	        let name_str = name.to_string_lossy();
183	        if name_str.starts_with('.') {
184	            continue;
185	        }
186	        if RESERVED_TEMPLATE_ENTRIES.contains(&name_str.as_ref()) {
187	            return Err(format!(
188	                "--use-template: {label} template '{}' contains reserved entry '{}'",
189	                p.display(),
190	                name_str
191	            )
192	            .into());
193	        }
194	    }
195	    Ok(())
196	}
197	
198	/// Validate both template paths (dual-repo mode). Thin wrapper over
199	/// `validate_template_one` kept for single-call ergonomics.
200	pub(crate) fn validate_templates(
201	    code: &Path,
202	    bot: &Path,
203	) -> Result<(), Box<dyn std::error::Error>> {
204	    validate_template_one("code", code)?;
205	    validate_template_one("bot", bot)?;
206	    Ok(())
207	}
